const config = {};

for (const item of $input.all()) {
  const source = item.json["SOURCE"] ? item.json["SOURCE"].trim().toUpperCase() : "";
  const apiKey = item.json["API KEY"] ? item.json["API KEY"].trim() : "";
  const rateLimit = parseInt(item.json["RATE_LIMIT_MS"]) || 1000; 
  const mail = item.json["PERSONAL_MAIL"] ? item.json["PERSONAL_MAIL"].trim() : "";
  const isActive = item.json["IS_ACTIVE"] === true || item.json["IS_ACTIVE"] === "TRUE";

  if (source === "OPEN ALEX") {
    config.openAlexKey = apiKey;
    config.openAlexDelay = rateLimit;
    config.openAlexMail = mail;
    config.openAlexActive = isActive;
  } else if (source === "PUBMED") {
    config.pubmedKey = apiKey;
    config.pubmedDelay = rateLimit;
    config.pubmedMail = mail;
    config.pubmedActive = isActive;
  } else if (source === "SEMANTIC_SCHOLAR" || source === "SEMANTIC SCHOLAR") {
    config.semanticKey = apiKey;
    config.semanticDelay = rateLimit;
    config.semanticMail = mail;
    config.semanticActive = isActive;
  } else if (source === "SCOPUS") {
    config.scopusKey = apiKey;
    config.scopusDelay = rateLimit;
    config.scopusMail = mail;
    config.scopusActive = isActive;
  } else if (source === "GOOGLE_SCHOLAR" || source === "GOOGLE SCHOLAR") {
    config.scholarKey = apiKey;
    config.scholarDelay = rateLimit;
    config.scholarMail = mail;
    config.scholarActive = isActive;
  }
}

return [{ json: config }];

const paper = $input.item.json;
const explodedAuthors = [];

const paperTitle = paper.title || "No Title";
const doi = paper.doi ? paper.doi.replace("https://doi.org/", "") : "No DOI";
const year = paper.publication_year || "n/d";
const isOpenAccess = paper.open_access ? paper.open_access.is_oa : false;

let fundingOA = "No data";
if (paper.grants && paper.grants.length > 0) {
    fundingOA = paper.grants.map(g => g.funder_display_name).join(" | ");
}

const authorships = paper.authorships || [];

if (authorships.length === 0) {
    explodedAuthors.push({
        json: { 
            PAPER_TITLE: paperTitle, 
            DOI: doi, 
            YEAR: year, 
            OPEN_ACCESS_OA: isOpenAccess, 
            FUNDING_OA: fundingOA, 
            AUTHOR_NAME: "Unknown", 
            AUTHOR_POS_OA: "Unknown", 
            IS_CORRESPONDING_OA: false, 
            AFFILIATION_OA: "No data", 
            GEO_COUNTRY_OA: "UNKNOWN", 
            AUTHOR_ID_OA: "NO_ID", 
            ORCID: "NO_ORCID" 
        }
    });
} else {
    authorships.forEach(auth => {
        let authorId = "NO_ID";
        let orcid = "NO_ORCID";

        if (auth.author) {
            if (auth.author.id) authorId = auth.author.id.split('/').pop();
            if (auth.author.orcid) orcid = auth.author.orcid.replace(/https?:\/\/orcid\.org\//, "");
        }

        const affiliations = auth.institutions && auth.institutions.length > 0
            ? auth.institutions.map(i => i.display_name).join(" | ")
            : "No affiliation";

        const countries = auth.institutions && auth.institutions.length > 0
            ? auth.institutions.map(i => i.country_code).filter(c => c).join(" | ")
            : "UNKNOWN";

        explodedAuthors.push({
            json: {
                PAPER_TITLE: paperTitle,
                DOI: doi,
                YEAR: year,
                OPEN_ACCESS_OA: isOpenAccess,
                FUNDING_OA: fundingOA,
                AUTHOR_NAME: auth.author ? auth.author.display_name : "Unknown",
                AUTHOR_POS_OA: auth.author_position || "Unknown",
                IS_CORRESPONDING_OA: auth.is_corresponding || false,
                AFFILIATION_OA: affiliations,
                GEO_COUNTRY_OA: countries,
                AUTHOR_ID_OA: authorId,
                ORCID: orcid
            }
        });
    });
}

return explodedAuthors;

const originalData = $('Loop Authors OpenAlex').item.json;
const authorProfile = items[0].json;

const hIndex = authorProfile.summary_stats ? authorProfile.summary_stats.h_index : 0;
const i10Index = authorProfile.summary_stats ? authorProfile.summary_stats.i10_index : 0;
const twoYrMean = authorProfile.summary_stats ? authorProfile.summary_stats['2yr_mean_citedness'] : 0;
const citations = authorProfile.cited_by_count || 0;
const worksCount = authorProfile.works_count || 0;

let keywords = "No data";
if (authorProfile.x_concepts && authorProfile.x_concepts.length > 0) {
    keywords = authorProfile.x_concepts.slice(0, 5).map(c => c.display_name).join(", ");
}

return {
    json: {
        ...originalData,
        WORKS_COUNT_OA: worksCount,
        CITATIONS_OA: citations,
        HINDEX_OA: hIndex,
        I10INDEX_OA: i10Index,
        '2YR_MEAN_OA': twoYrMean,
        KEYWORDS_OA: keywords
    }
};

const originalData = $('Loop Authors OpenAlex').item.json;

return {
    json: {
        ...originalData, 
        WORKS_COUNT_OA: 0,
        CITATIONS_OA: 0,
        HINDEX_OA: 0,
        I10INDEX_OA: 0,
        '2YR_MEAN_OA': 0,
        KEYWORDS_OA: "No data"
    }
};

const allAuthorsOA = $('Check PubMed Active').all().map(item => item.json);
const pubmedData = $input.item.json.PubmedArticleSet?.PubmedArticle;

let pmid = "N/A";
let meshPM = "No data";
let fundingPM = "No data";
let authorsPM = [];

if (pubmedData) {
    const medline = pubmedData.MedlineCitation;
    pmid = medline?.PMID?._ || medline?.PMID || "N/A";

    if (medline?.MeshHeadingList?.MeshHeading) {
        let meshes = medline.MeshHeadingList.MeshHeading;
        if (!Array.isArray(meshes)) meshes = [meshes];
        meshPM = meshes.slice(0, 5).map(m => m.DescriptorName._ || m.DescriptorName).join(", ");
    }

    // FUNDING P_M
    if (medline?.Article?.GrantList?.Grant) {
        let grants = medline.Article.GrantList.Grant;
        if (!Array.isArray(grants)) grants = [grants];
        fundingPM = grants.map(g => g.Agency).filter(a => a).join(" | ");
    }

    if (medline?.Article?.AuthorList?.Author) {
        let auths = medline.Article.AuthorList.Author;
        if (!Array.isArray(auths)) auths = [auths];
        authorsPM = auths.map((a, idx) => ({
            name: `${a.ForeName || ''} ${a.LastName || ''}`.trim().toLowerCase(),
            rawName: `${a.ForeName || ''} ${a.LastName || ''}`.trim(),
            affiliation: a.AffiliationInfo?.Affiliation || (Array.isArray(a.AffiliationInfo) ? a.AffiliationInfo[0]?.Affiliation : "No affiliation"),
            pos: idx === 0 ? "first" : (idx === auths.length - 1 ? "last" : "middle")
        }));
    }
}

let finalRows = allAuthorsOA.map(oa => {
    const matchPM = authorsPM.find(pm => pm.name.includes(oa.AUTHOR_NAME.toLowerCase()) || oa.AUTHOR_NAME.toLowerCase().includes(pm.name));

    return {
        json: {
            ...oa,
            PMID_PM: pmid,
            MESH_PM: meshPM,
            FUNDING_PM: fundingPM,
            AUTHOR_NAME_PM: matchPM ? matchPM.rawName : "NOT_FOUND_IN_PM",
            AFFILIATION_PM: matchPM ? matchPM.affiliation : "N/A"
        }
    };
});

authorsPM.forEach(pm => {
    const existsInOA = allAuthorsOA.some(oa => oa.AUTHOR_NAME.toLowerCase().includes(pm.name) || pm.name.includes(oa.AUTHOR_NAME.toLowerCase()));

    if (!existsInOA && pm.name !== "") {
        const baseData = allAuthorsOA[0]; 

        finalRows.push({
            json: {
                PAPER_TITLE: baseData.PAPER_TITLE,
                DOI: baseData.DOI,
                YEAR: baseData.YEAR,
                OPEN_ACCESS_OA: baseData.OPEN_ACCESS_OA,
                FUNDING_OA: baseData.FUNDING_OA,

                AUTHOR_NAME: pm.rawName,
                AUTHOR_POS_OA: pm.pos,
                IS_CORRESPONDING_OA: false,
                AUTHOR_ID_OA: "PubMed_Fallback",
                ORCID: "NO_ORCID",

                AFFILIATION_OA: "MISSING_IN_OA",
                GEO_COUNTRY_OA: "UNKNOWN",
                WORKS_COUNT_OA: 0,
                CITATIONS_OA: 0,
                HINDEX_OA: 0,
                I10INDEX_OA: 0,
                '2YR_MEAN_OA': 0,
                KEYWORDS_OA: "No data",

                PMID_PM: pmid,
                MESH_PM: meshPM,
                FUNDING_PM: fundingPM,
                AUTHOR_NAME_PM: pm.rawName,
                AFFILIATION_PM: pm.affiliation
            }
        });
    }
});

return finalRows;

const allAuthors = $input.all().map(item => item.json);
return allAuthors.map(author => {
    return {
        json: {
            ...author,
            PMID_PM: "N/A",
            MESH_PM: "No data",
            FUNDING_PM: "No data",
            AUTHOR_NAME_PM: "SKIP",
            AFFILIATION_PM: "N/A"
        }
    };
});

const allAuthors = $('Check Scopus Active').all().map(item => item.json);
const scopusEntry = $input.item.json['search-results']?.entry?.[0];

let fundingSC = "No data";
let scopusAuthors = [];

if (scopusEntry) {
    fundingSC = scopusEntry['fund-sponsor'] || "No data";

    if (scopusEntry.author) {
        scopusAuthors = scopusEntry.author.map(a => ({
            name: (`${a['given-name'] || ''} ${a.surname || ''}`).trim().toLowerCase(),
            rawName: (`${a['given-name'] || ''} ${a.surname || ''}`).trim(),
            scopusId: a.authid || "NO_ID_SC",

            affiliation: a.afid ? (Array.isArray(a.afid) ? a.afid[0]['$'] : a.afid['$']) : "No affiliation"
        }));
    }
}

let finalRows = allAuthors.map(author => {

    const matchSC = scopusAuthors.find(sc => sc.name.includes(author.AUTHOR_NAME.toLowerCase()) || author.AUTHOR_NAME.toLowerCase().includes(sc.name));

    return {
        json: {
            ...author,
            AUTHOR_ID_SC: matchSC ? matchSC.scopusId : "NOT_FOUND_IN_SC",
            AUTHOR_NAME_SC: matchSC ? matchSC.rawName : "SKIP",
            AFFILIATION_SC: matchSC ? matchSC.affiliation : "N/A",
            FUNDING_SC: fundingSC
        }
    };
});

scopusAuthors.forEach(sc => {
    const existsInFlow = allAuthors.some(auth => auth.AUTHOR_NAME.toLowerCase().includes(sc.name) || sc.name.includes(auth.AUTHOR_NAME.toLowerCase()));

    if (!existsInFlow && sc.name !== "") {
        const baseData = allAuthors[0]; 

        finalRows.push({
            json: {
                PAPER_TITLE: baseData.PAPER_TITLE,
                DOI: baseData.DOI,
                YEAR: baseData.YEAR,
                AUTHOR_NAME: sc.rawName,

                AUTHOR_POS_OA: "Unknown",
                IS_CORRESPONDING_OA: false,
                AUTHOR_ID_OA: "Scopus_Fallback",
                ORCID: "NO_ORCID",
                OPEN_ACCESS_OA: false,
                FUNDING_OA: "No data",
                AFFILIATION_OA: "MISSING_IN_OA",
                GEO_COUNTRY_OA: "UNKNOWN",
                WORKS_COUNT_OA: 0,
                CITATIONS_OA: 0,
                HINDEX_OA: 0,
                I10INDEX_OA: 0,
                '2YR_MEAN_OA': 0,
                KEYWORDS_OA: "No data",
                PMID_PM: "N/A",
                MESH_PM: "No data",
                FUNDING_PM: "No data",
                AUTHOR_NAME_PM: "SKIP",
                AFFILIATION_PM: "N/A",

                AUTHOR_ID_SC: sc.scopusId,
                AUTHOR_NAME_SC: sc.rawName,
                AFFILIATION_SC: sc.affiliation,
                FUNDING_SC: fundingSC
            }
        });
    }
});

return finalRows;

const allAuthors = $input.all().map(item => item.json);
return allAuthors.map(author => {
    return {
        json: {
            ...author,
            AUTHOR_ID_SC: "N/A",
            AUTHOR_NAME_SC: "SKIP",
            AFFILIATION_SC: "N/A",
            FUNDING_SC: "No data"
        }
    };
});

const allAuthors = $('Check Semantic Active').all().map(item => item.json);
const ssPaper = $input.item.json;

let inflCitations = ssPaper.influentialCitationCount || 0;
let citationContexts = "N/A"; 

let ssAuthors = ssPaper.authors || [];

const normalizeName = (name) => {
    if (!name) return "";
    return name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().replace(/[^a-z]/g, '');
};

let finalRows = allAuthors.map(author => {
    const authorNameNorm = normalizeName(author.AUTHOR_NAME);

    let matchSS = null;
    if (authorNameNorm !== "") {
        matchSS = ssAuthors.find(ss => {
            const ssNameNorm = normalizeName(ss.name);
            if (ssNameNorm === "") return false;
            // Evaluamos contención mutua para atrapar "Rashmi K Ambasta" vs "Rashmi Ambasta"
            return ssNameNorm.includes(authorNameNorm) || authorNameNorm.includes(ssNameNorm);
        });
    }

    let orcidSS = "NO_ORCID_SS";
    if (matchSS && matchSS.externalIds && matchSS.externalIds.ORCID) {
        orcidSS = matchSS.externalIds.ORCID;
    }

    return {
        json: {
            ...author, 
            INFLUENTIAL_CITATIONS_SS: inflCitations,
            CITATION_CONTEXTS_SS: citationContexts,
            AUTHOR_ID_SS: matchSS ? (matchSS.authorId || "NO_ID_SS") : "NOT_FOUND_IN_SS",
            AUTHOR_NAME_SS: matchSS ? matchSS.name : "NOT_FOUND_IN_SS",
            ORCID_SS: orcidSS,
            HINDEX_SS: matchSS ? (matchSS.hIndex || 0) : 0,
            CITATIONS_SS: matchSS ? (matchSS.citationCount || 0) : 0
        }
    };
});

ssAuthors.forEach(ss => {
    if (!ss.name || ss.name.trim() === "") return;
    const ssNameNorm = normalizeName(ss.name);

    const existsInFlow = allAuthors.some(auth => {
        const authNameNorm = normalizeName(auth.AUTHOR_NAME);
        if (authNameNorm === "") return false;
        return authNameNorm.includes(ssNameNorm) || ssNameNorm.includes(authNameNorm);
    });

    if (!existsInFlow) {
        const baseData = allAuthors[0]; 

        let orcidSS = "NO_ORCID_SS";
        if (ss.externalIds && ss.externalIds.ORCID) {
            orcidSS = ss.externalIds.ORCID;
        }

        finalRows.push({
            json: {
                PAPER_TITLE: baseData.PAPER_TITLE,
                DOI: baseData.DOI,
                YEAR: baseData.YEAR,
                AUTHOR_NAME: ss.name,

                AUTHOR_POS_OA: "Unknown",
                IS_CORRESPONDING_OA: false,
                AUTHOR_ID_OA: "Semantic_Fallback",
                ORCID: "NO_ORCID", 
                OPEN_ACCESS_OA: false,
                FUNDING_OA: "No data",
                AFFILIATION_OA: "MISSING_IN_OA",
                GEO_COUNTRY_OA: "UNKNOWN",
                WORKS_COUNT_OA: 0,
                CITATIONS_OA: 0,
                HINDEX_OA: 0,
                I10INDEX_OA: 0,
                '2YR_MEAN_OA': 0,
                KEYWORDS_OA: "No data",
                PMID_PM: "N/A",
                MESH_PM: "No data",
                FUNDING_PM: "No data",
                AUTHOR_NAME_PM: "SKIP",
                AFFILIATION_PM: "N/A",
                AUTHOR_ID_SC: "N/A",
                AUTHOR_NAME_SC: "SKIP",
                AFFILIATION_SC: "N/A",
                FUNDING_SC: "No data",
                INFLUENTIAL_CITATIONS_SS: inflCitations,
                CITATION_CONTEXTS_SS: citationContexts,
                AUTHOR_ID_SS: ss.authorId || "NO_ID_SS",
                AUTHOR_NAME_SS: ss.name,
                ORCID_SS: orcidSS, 
                HINDEX_SS: ss.hIndex || 0,
                CITATIONS_SS: ss.citationCount || 0
            }
        });
    }
});

return finalRows;

const allAuthors = $input.all().map(item => item.json);
return allAuthors.map(author => {
    return {
        json: {
            ...author,
            INFLUENTIAL_CITATIONS_SS: 0,
            CITATION_CONTEXTS_SS: "No data",
            AUTHOR_ID_SS: "N/A",
            AUTHOR_NAME_SS: "SKIP",
            HINDEX_SS: 0,
            CITATIONS_SS: 0
        }
    };
});

const originalData = $('Loop Scopus Deep Dive').item.json;
let authorProfile = {};

try {
    const response = items[0].json['author-retrieval-response'];
    authorProfile = Array.isArray(response) ? response[0] : response;
} catch(e) {}

let subjectAreas = "No data";
let seniority = "Unknown";
let careerLength = 0;
let citationsSC = 0;
let hindexSC = 0;
let docCountSC = 0;

if (authorProfile && authorProfile.coredata) {
    const core = authorProfile.coredata;
    citationsSC = core['citation-count'] || 0;
    docCountSC = core['document-ent-count'] || 0;

    let hData = authorProfile['h-index'];
    if (hData) hindexSC = typeof hData === 'object' ? (hData['$'] || hData['value']) : hData;

    if (authorProfile['subject-areas'] && authorProfile['subject-areas']['subject-area']) {
        let subjects = authorProfile['subject-areas']['subject-area'];
        if (!Array.isArray(subjects)) subjects = [subjects];

        subjectAreas = subjects.map(s => s['$'] || s['@abbrev'] || "").filter(Boolean).join(" | ");
    }

    let pubRange = authorProfile['author-profile']?.['publication-range'];
    if (pubRange && pubRange['@first']) {
        let firstYear = parseInt(pubRange['@first']);
        if (!isNaN(firstYear)) {
            careerLength = new Date().getFullYear() - firstYear;
            if (careerLength >= 15) seniority = `Senior (${careerLength} yrs)`;
            else if (careerLength >= 5) seniority = `Mid-level (${careerLength} yrs)`;
            else seniority = `Early-career (${careerLength} yrs)`;
        }
    }
}

return {
    json: {
        ...originalData,
        HINDEX_SC: hindexSC || 0,
        CITATIONS_SC: citationsSC,
        DOC_COUNT_SC: docCountSC,
        SUBJECT_AREAS_SC: subjectAreas,
        SENIORITY_SC: seniority         
    }
};

const originalData = $('Loop Scopus Deep Dive').item.json;

return {
    json: {
        ...originalData,
        HINDEX_SC: 0,
        CITATIONS_SC: 0,
        DOC_COUNT_SC: 0,
        SUBJECT_AREAS_SC: "No data",
        SENIORITY_SC: "Unknown"
    }
};

const allAuthors = $input.all().map(item => item.json);

return allAuthors.map(author => {
    return {
        json: {
            ...author,
            AUTHOR_ID_GS: "N/A (Disabled)",
            INTERESTS_GS: "N/A"
        }
    };
});

const staticData = $getWorkflowStaticData("global");
if (!staticData.genderCache) staticData.genderCache = {};

const author = $input.item.json;
let gender = "Unknown";

// 1. Filtro Institucional (Regex)
const instRegex = /(group|network|study|collaborators|team|consortium|committee)/i;
if (instRegex.test(author.AUTHOR_NAME)) {
    return { json: { ...author, GENDER: "N/A", _FIRST_NAME: "skip" } };
}

const firstName = author.AUTHOR_NAME.split(" ")[0].toLowerCase().replace(/[^a-z]/g, '');

if (staticData.genderCache[firstName]) {
    gender = staticData.genderCache[firstName];
}

return { json: { ...author, GENDER: gender, _FIRST_NAME: firstName } };

const originalData = $('Has ORCID?').item.json;
let employment = "No employment data listed in ORCID";

try {
    const employments = $input.item.json['employment-summary'];
    if (employments && employments.length > 0) {
        const latest = employments[0];
        employment = `${latest.organization.name} (${latest['department-name'] || 'No department'})`;
    }
} catch(e) {}

return { json: { ...originalData, ORCID_EMPLOYMENT: employment } };

const items = $input.all().map(item => item.json);
const mergedAuthors = [];
const staticData = $getWorkflowStaticData("global");

const getParts = (name) => {
    if (!name) return { clean: "", lastName: "", firstInitial: "" };
    const noAccents = name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().replace(/[^a-z\s]/g, '').trim();
    const parts = noAccents.split(/\s+/);
    return { clean: noAccents.replace(/\s/g, ''), lastName: parts[parts.length - 1] || "", firstInitial: parts[0] ? parts[0][0] : "" };
};

items.forEach(item => {
    const curr = getParts(item.AUTHOR_NAME);
    if (curr.clean === "") return;

    let matchIndex = mergedAuthors.findIndex(existing => {
        const ex = getParts(existing.AUTHOR_NAME);
        if (curr.clean === ex.clean || curr.clean.includes(ex.clean) || ex.clean.includes(curr.clean)) return true;
        if (curr.lastName !== "" && curr.lastName === ex.lastName && curr.firstInitial === ex.firstInitial) return true;
        return false;
    });

    if (matchIndex === -1) {
        mergedAuthors.push({ ...item });
        matchIndex = mergedAuthors.length - 1;
    } 

    const existing = mergedAuthors[matchIndex];

    if (item.AUTHOR_ID_SC && item.AUTHOR_ID_SC !== "N/A" && item.AUTHOR_ID_SC !== "NOT_FOUND_IN_SC") {
        existing.AUTHOR_ID_SC = item.AUTHOR_ID_SC;
        existing.HINDEX_SC = Math.max(existing.HINDEX_SC || 0, item.HINDEX_SC || 0);
        existing.CITATIONS_SC = Math.max(existing.CITATIONS_SC || 0, item.CITATIONS_SC || 0);
        if (!existing.SUBJECT_AREAS_SC || existing.SUBJECT_AREAS_SC === "No data") existing.SUBJECT_AREAS_SC = item.SUBJECT_AREAS_SC;
        if (!existing.SENIORITY_SC || existing.SENIORITY_SC === "Unknown") existing.SENIORITY_SC = item.SENIORITY_SC;
    }
    if (item.AUTHOR_ID_SS && item.AUTHOR_ID_SS !== "N/A" && item.AUTHOR_ID_SS !== "NOT_FOUND_IN_SS") {
        existing.AUTHOR_ID_SS = item.AUTHOR_ID_SS;
        existing.HINDEX_SS = Math.max(existing.HINDEX_SS || 0, item.HINDEX_SS || 0);
        existing.CITATIONS_SS = Math.max(existing.CITATIONS_SS || 0, item.CITATIONS_SS || 0);
    }

    const scholarMemory = staticData.scholarCache ? staticData.scholarCache[item.AUTHOR_NAME] : null;
    if (scholarMemory && scholarMemory.authorIdGS && scholarMemory.authorIdGS !== "NOT_FOUND") {
        existing.AUTHOR_ID_GS = scholarMemory.authorIdGS;
        existing.INTERESTS_GS = scholarMemory.interestsGS;
    }

    if (existing.ORCID === "NO_ORCID" && item.ORCID && item.ORCID !== "NO_ORCID") existing.ORCID = item.ORCID;
});

return mergedAuthors.map(author => ({ json: author }));

const originalData = $('Loop Scholar Deep Dive').item.json;
const searchResults = ($input.item.json && $input.item.json.profiles) ? $input.item.json.profiles : [];

let interestsGS = "NOT_INDEXED_IN_GS";
let authorIdGS = "NOT_FOUND";

if (searchResults.length > 0) {
    const profile = searchResults[0];
    authorIdGS = profile.author_id || "NO_ID";
    if (profile.interests) interestsGS = profile.interests.map(i => i.title).join(" | ");
} else if ($input.item.json.organic_results && $input.item.json.organic_results.length > 0) {
    const paper = $input.item.json.organic_results[0];
    if (paper.publication_info && paper.publication_info.authors) {
        const match = paper.publication_info.authors.find(a => a.name.toLowerCase().includes(originalData.AUTHOR_NAME.toLowerCase().split(" ")[0]));
        if (match && match.author_id) { authorIdGS = match.author_id; interestsGS = "Extracted from papers"; }
    }
}

const staticData = $getWorkflowStaticData("global");
if (!staticData.scholarCache) staticData.scholarCache = {};
staticData.scholarCache[originalData.AUTHOR_NAME] = { authorIdGS, interestsGS };

return { json: originalData };

const authorData = $('Needs Genderize?').item.json;
const genderData = $input.item.json;

let finalGender = "Unknown";
let prob = genderData.probability || 0;

if (genderData.gender && prob >= 0.8) {
    finalGender = genderData.gender.charAt(0).toUpperCase() + genderData.gender.slice(1);

    const staticData = $getWorkflowStaticData("global");
    staticData.genderCache[authorData._FIRST_NAME] = finalGender;
}

delete authorData._FIRST_NAME;
return { json: { ...authorData, GENDER: finalGender } };

